// Obyekt destrukturasiyası
let kitchen = {
  chefName: "Aysel",
  dish: "Omlet",
  tool: "tava"
};

// Ənənəvi üsul
let chef = kitchen.chefName;
let dish = kitchen.dish;
console.log(chef, dish); // nəticə: Aysel Omlet

// Destrukturasiya ilə
let { chefName, dish } = kitchen;
console.log(chefName, dish); // nəticə: Aysel Omlet

// Fərqli dəyişən adları ilə
let { chefName: cookName, dish: meal } = kitchen;
console.log(cookName, meal); // nəticə: Aysel Omlet

// Varsayılan dəyərlər
let { tool, oven = "yoxdur" } = kitchen;
console.log(tool, oven); // nəticə: tava yoxdur

// Array destrukturasiyası
let breakfastList = ["yumurta", "süd", "çörək", "pendir"];

// Ənənəvi üsul
let first = breakfastList[0];
let second = breakfastList[1];
console.log(first, second); // nəticə: yumurta süd

// Destrukturasiya ilə
let [item1, item2] = breakfastList;
console.log(item1, item2); // nəticə: yumurta süd

// Bəzi elementləri atlamaq
let [,,item3] = breakfastList;
console.log(item3); // nəticə: çörək

// Varsayılan dəyərlər
let [item5 = "bal"] = breakfastList;
console.log(item5); // nəticə: bal

// Qalan elementlər üçün rest operator
let [firstItem, ...rest] = breakfastList;
console.log(firstItem, rest); // nəticə: yumurta ["süd", "çörək", "pendir"]

// Daxili destrukturasiya
let kitchen = {
  chef: { name: "Aysel", experience: 5 },
  ingredients: ["yumurta", "süd"]
};
let { chef: { name, experience }, ingredients: [firstIng] } = kitchen;
console.log(name, experience, firstIng); // nəticə: Aysel 5 yumurta

// Funksiya parametrində destrukturasiya
function cook({ dish, tool }) {
  return `Hazırlanır: ${dish} (${tool})`;
}
console.log(cook(kitchen)); // nəticə: Hazırlanır: Omlet (tava)

// Dəyişən mübadiləsi
let a = "yumurta", b = "süd";
[a, b] = [b, a];
console.log(a, b); // nəticə: süd yumurta

// Səhv açar nümunəsi
let { wrongKey } = kitchen;
console.log(wrongKey); // nəticə: undefined

// Çox daxili destrukturasiya
let { chef: { name: chefName, experience: years } } = kitchen;
console.log(chefName, years); // nəticə: Aysel 5

// Varsayılan dəyər səhvi
let { tool: pan = "kiçik" } = kitchen;
console.log(pan); // nəticə: tava (varsayılan dəyər istifadə olunmur)

