// Object destructuring
let kitchen = {
  chefName: "Aysel",
  dish: "Omelette",
  tool: "pan"
};

// Traditional way
let chef = kitchen.chefName;
let dish = kitchen.dish;
console.log(chef, dish); // Output: Aysel Omelette

// With destructuring
let { chefName, dish } = kitchen;
console.log(chefName, dish); // Output: Aysel Omelette

// Renaming variables
let { chefName: cookName, dish: meal } = kitchen;
console.log(cookName, meal); // Output: Aysel Omelette

// Default values
let { tool, oven = "none" } = kitchen;
console.log(tool, oven); // Output: pan none

// Array destructuring
let breakfastList = ["eggs", "milk", "bread", "cheese"];

// Traditional way
let first = breakfastList[0];
let second = breakfastList[1];
console.log(first, second); // Output: eggs milk

// With destructuring
let [item1, item2] = breakfastList;
console.log(item1, item2); // Output: eggs milk

// Skipping elements
let [,,item3] = breakfastList;
console.log(item3); // Output: bread

// Default values
let [item5 = "honey"] = breakfastList;
console.log(item5); // Output: honey

// Rest operator for remaining elements
let [firstItem, ...rest] = breakfastList;
console.log(firstItem, rest); // Output: eggs ["milk", "bread", "cheese"]

// Nested destructuring
let kitchen = {
  chef: { name: "Aysel", experience: 5 },
  ingredients: ["eggs", "milk"]
};
let { chef: { name, experience }, ingredients: [firstIng] } = kitchen;
console.log(name, experience, firstIng); // Output: Aysel 5 eggs

// Destructuring in function parameters
function cook({ dish, tool }) {
  return `Cooking: ${dish} (${tool})`;
}
console.log(cook(kitchen)); // Output: Cooking: Omelette (pan)

// Variable swapping
let a = "eggs", b = "milk";
[a, b] = [b, a];
console.log(a, b); // Output: milk eggs

// Invalid key example
let { wrongKey } = kitchen;
console.log(wrongKey); // Output: undefined

// Deeply nested destructuring
let { chef: { name: chefName, experience: years } } = kitchen;
console.log(chefName, years); // Output: Aysel 5

// Default value issue
let { tool: pan = "small" } = kitchen;
console.log(pan); // Output: pan (default not used)

