// Деструктуризация объектов
let kitchen = {
  chefName: "Айсель",
  dish: "Омлет",
  tool: "сковорода"
};

// Традиционный способ
let chef = kitchen.chefName;
let dish = kitchen.dish;
console.log(chef, dish); // Вывод: Айсель Омлет

// С деструктуризацией
let { chefName, dish } = kitchen;
console.log(chefName, dish); // Вывод: Айсель Омлет

// Переименование переменных
let { chefName: cookName, dish: meal } = kitchen;
console.log(cookName, meal); // Вывод: Айсель Омлет

// Значения по умолчанию
let { tool, oven = "нет" } = kitchen;
console.log(tool, oven); // Вывод: сковорода нет

// Деструктуризация массивов
let breakfastList = ["яйца", "молоко", "хлеб", "сыр"];

// Традиционный способ
let first = breakfastList[0];
let second = breakfastList[1];
console.log(first, second); // Вывод: яйца молоко

// С деструктуризацией
let [item1, item2] = breakfastList;
console.log(item1, item2); // Вывод: яйца молоко

// Пропуск элементов
let [,,item3] = breakfastList;
console.log(item3); // Вывод: хлеб

// Значения по умолчанию
let [item5 = "мёд"] = breakfastList;
console.log(item5); // Вывод: мёд

// Оператор rest для остальных элементов
let [firstItem, ...rest] = breakfastList;
console.log(firstItem, rest); // Вывод: яйца ["молоко", "хлеб", "сыр"]

// Вложенная деструктуризация
let kitchen = {
  chef: { name: "Айсель", experience: 5 },
  ingredients: ["яйца", "молоко"]
};
let { chef: { name, experience }, ingredients: [firstIng] } = kitchen;
console.log(name, experience, firstIng); // Вывод: Айсель 5 яйца

// Деструктуризация в параметрах функции
function cook({ dish, tool }) {
  return `Готовим: ${dish} (${tool})`;
}
console.log(cook(kitchen)); // Вывод: Готовим: Омлет (сковорода)

// Обмен переменных
let a = "яйца", b = "молоко";
[a, b] = [b, a];
console.log(a, b); // Вывод: молоко яйца

// Пример неверного ключа
let { wrongKey } = kitchen;
console.log(wrongKey); // Вывод: undefined

// Глубоко вложенная деструктуризация
let { chef: { name: chefName, experience: years } } = kitchen;
console.log(chefName, years); // Вывод: Айсель 5

// Проблема со значением по умолчанию
let { tool: pan = "маленькая" } = kitchen;
console.log(pan); // Вывод: сковорода (значение по умолчанию не используется)

